def check_dict_case(dict):
    if not dict:
        return False

    all_lower = True
    all_upper = True

    for key in dict:
        if not isinstance(key, str):
            return False
        if key!= key.lower():
            all_lower = False
        if key!= key.upper():
            all_upper = False

    return all_lower or all_upper

def f(n):
    result = []
    for i in range(1, n + 1):
        if i % 2 == 0:
            factorial = 1
            for j in range(1, i + 1):
                factorial *= j
            result.append(factorial)
        else:
            sum = 0
            for j in range(1, i + 1):
                sum += j
            result.append(sum)
    return result

